example.code:
const browser = await puppeteer.launch({
  headless: 'new',
  args: ['--no-sandbox', '--disable-setuid-sandbox',
         '--disable-dev-shm-usage', '--disable-gpu']
});

// Navigate and wait for stability
await page.goto('https://example.com', { waitUntil: 'networkidle0', timeout: 30000 });

// Wait then interact
await page.waitForSelector('#button', { visible: true, timeout: 5000 });
await page.click('#button');

// Extract multiple items
const items = await page.$$eval('.product', products =>
  products.map(p => ({
    name: p.querySelector('.name')?.textContent?.trim(),
    price: p.querySelector('.price')?.textContent?.trim(),
  }))
);

// Full page screenshot
await page.screenshot({ path: 'full.png', fullPage: true });

// Element screenshot
const el = await page.$('#chart');
await el.screenshot({ path: 'chart.png' });

// PDF generation
await page.pdf({
  path: 'document.pdf', format: 'A4', printBackground: true,
  margin: { top: '1cm', right: '1cm', bottom: '1cm', left: '1cm' }
});

// Save session
const cookies = await page.cookies();
fs.writeFileSync('cookies.json', JSON.stringify(cookies));

// Restore session
const saved = JSON.parse(fs.readFileSync('cookies.json'));
await page.setCookie(...saved);
